  ('elementary-d0d1b9a2-moex-00665', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-111-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲建設公司目前有10個保證型保固合約，依甲公司過去經驗顯示，有50%會請求保固，每建案之保固成 本為$400,000，則甲公司應認列之負債準備為何？', '["$4,000,000", "$2,000,000", "$900,000", "屬或有負債，僅需附註揭露"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:48+00:00", "source_pdf_sha1": "50d6b891a10f", "answer_pdf_sha1": "3bcd4c20ba2b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
